            "toggleEnabled": "false",
            "customMarkers": "[\"{\\\"name\\\":\\\"ENTRANCE-UP\\\",\\\"image\\\":\\\"BattleCursor_B - Copy\\\"}\"]",
            "playerMarkerImage": "",
            "showInMenu": "true",
